#include "SoftwareSpecInstance.h"




//Can't use non pointer global instance because it causes a recursion loop during registration
//if this code is in a dll.  Has to do with the amount of autogenerated code.
GlobalSoftwareSpec* g_pSoftwareSpec = NULL;


GlobalSoftwareSpec::GlobalSoftwareSpec():
	GlobalSoftwareSpecLock(CreateMutex(0,0,0))
{
	SafeMutex mutex(GlobalSoftwareSpecLock);

	// is an autogenerated file with the Software Spec for all products.
	#include "SoftwareSpecInitialize.h"
}

GlobalSoftwareSpec::~GlobalSoftwareSpec()
{
	{
	SafeMutex mutex(GlobalSoftwareSpecLock);
	}
	if (GlobalSoftwareSpecLock!=NULL)
	{
		CloseHandle(GlobalSoftwareSpecLock);
		GlobalSoftwareSpecLock = NULL;
	}
}

Lic_PackageAttribs::Lic_SoftwareSpecAttribs GlobalSoftwareSpec::GetSoftwareSpec()
{
	SafeMutex mutex(GlobalSoftwareSpecLock);
	return softwareSpec;
}

void GlobalSoftwareSpec::SetSoftwareSpec(Lic_PackageAttribs::Lic_SoftwareSpecAttribs newSoftwareSpec)
{
   SafeMutex mutex(GlobalSoftwareSpecLock);
   softwareSpec.InitFromString(newSoftwareSpec.ToString());
}